using Microsoft.EntityFrameworkCore;
class AppDbContext : DbContext
{
    public DbSet<Order> Orders => Set<Order>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: HasData() no longer accepts expressions
        // like DateTime.UtcNow that are evaluated at migration time.
        // Use a fixed constant for seed data.
        modelBuilder.Entity<Order>().HasData(
            new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });
    }
}
class Order { public int Id { get; set; } public DateTime CreatedAt { get; set; } }

// --- Cosmos DB context demonstrating EF Core 9 breaking changes ---
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "ShopDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: EF Core 9 Cosmos provider now uses "$type" as the
        // default discriminator property instead of "Discriminator".
        // For existing documents that already use "Discriminator", explicitly
        // configure the property name to maintain backward compatibility.
        modelBuilder.Entity<Product>()
            .HasDiscriminatorInJsonProperty("Discriminator");

        modelBuilder.Entity<Product>().ToContainer("Products");
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
    public string PartitionKey { get; set; } = null!;
}

class CosmosQueryService
{
    // Breaking change 2: EF Core 9 Cosmos provider removed synchronous query
    // support. All Cosmos queries must use async (ToListAsync, FirstAsync, etc.)
    // Previously: db.Products.ToList() — now throws InvalidOperationException.
    public async Task<List<Product>> GetProductsAsync(CosmosDbContext db)
    {
        return await db.Products.ToListAsync();
    }

    public async Task<Product?> GetProductByNameAsync(CosmosDbContext db, string name)
    {
        return await db.Products.FirstOrDefaultAsync(p => p.Name == name);
    }
}

